import React, { useRef, useEffect } from 'react';
import { View, StyleSheet, ScrollView, TouchableOpacity, Animated, Dimensions } from 'react-native';
import { Text } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';
import AsyncStorage from '@react-native-async-storage/async-storage';

const { width } = Dimensions.get('window');

export default function ProfileScreen({ navigation }) {
  const scrollY = useRef(new Animated.Value(0)).current;
  const headerAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    Animated.timing(headerAnim, { toValue: 1, duration: 600, useNativeDriver: true }).start();
  }, []);

  const handleLogout = async () => {
    await AsyncStorage.clear();
    alert('Logged out successfully. Please restart the app.');
  };

  const menuSections = [
    {
      title: 'Account',
      items: [
        { icon: 'account-edit-outline', label: 'Edit Profile', color: '#00C853' },
        { icon: 'map-marker-outline', label: 'Addresses', color: '#42A5F5' },
        { icon: 'credit-card-outline', label: 'Payment Methods', color: '#FF9800' },
      ],
    },
    {
      title: 'Preferences',
      items: [
        { icon: 'bell-outline', label: 'Notifications', color: '#E040FB' },
        { icon: 'translate', label: 'Language', subtitle: 'English', color: '#00BCD4' },
      ],
    },
    {
      title: 'Support',
      items: [
        { icon: 'help-circle-outline', label: 'Help Center', color: '#69F0AE' },
        { icon: 'shield-check-outline', label: 'Privacy Policy', color: '#7C4DFF' },
        { icon: 'file-document-outline', label: 'Terms & Conditions', color: '#FFD54F' },
      ],
    },
  ];

  const avatarScale = scrollY.interpolate({ inputRange: [0, 100], outputRange: [1, 0.75], extrapolate: 'clamp' });

  return (
    <LinearGradient colors={['#0a1a0f', '#0d2818', '#0a1a0f']} style={styles.container}>
      <Animated.ScrollView
        showsVerticalScrollIndicator={false}
        onScroll={Animated.event([{ nativeEvent: { contentOffset: { y: scrollY } } }], { useNativeDriver: true })}
        scrollEventThrottle={16}
      >
        {/* Profile Header */}
        <Animated.View style={[styles.header, { opacity: headerAnim }]}>
          <LinearGradient colors={['rgba(0,200,83,0.15)', 'transparent']} style={styles.headerGradient}>
            <Animated.View style={[styles.avatarContainer, { transform: [{ scale: avatarScale }] }]}>
              <LinearGradient colors={['#00C853', '#00E676']} style={styles.avatar}>
                <Text style={styles.avatarText}>JD</Text>
              </LinearGradient>
              <TouchableOpacity style={styles.editAvatarBtn}>
                <Icon name="camera" size={14} color="#fff" />
              </TouchableOpacity>
            </Animated.View>
            <Text style={styles.name}>John Doe</Text>
            <Text style={styles.email}>john.doe@example.com</Text>
            <Text style={styles.phone}>+91 98765 43210</Text>

            {/* Stats Row */}
            <View style={styles.statsRow}>
              <View style={styles.statItem}>
                <Text style={styles.statValue}>12</Text>
                <Text style={styles.statLabel}>Orders</Text>
              </View>
              <View style={styles.statDivider} />
              <View style={styles.statItem}>
                <Text style={styles.statValue}>3</Text>
                <Text style={styles.statLabel}>Addresses</Text>
              </View>
              <View style={styles.statDivider} />
              <View style={styles.statItem}>
                <Text style={styles.statValue}>₹2.4k</Text>
                <Text style={styles.statLabel}>Spent</Text>
              </View>
            </View>
          </LinearGradient>
        </Animated.View>

        {/* Menu Sections */}
        {menuSections.map((section, sIdx) => (
          <AnimatedSection key={sIdx} section={section} index={sIdx} />
        ))}

        {/* Logout */}
        <View style={styles.logoutContainer}>
          <TouchableOpacity onPress={handleLogout} activeOpacity={0.7} style={styles.logoutButton}>
            <Icon name="logout" size={20} color="#FF5252" />
            <Text style={styles.logoutText}>Logout</Text>
          </TouchableOpacity>
        </View>

        <Text style={styles.version}>Version 1.0.0</Text>
        <View style={{ height: 100 }} />
      </Animated.ScrollView>
    </LinearGradient>
  );
}

function AnimatedSection({ section, index }) {
  const anim = useRef(new Animated.Value(0)).current;
  useEffect(() => {
    Animated.spring(anim, { toValue: 1, delay: (index + 1) * 150, tension: 50, friction: 8, useNativeDriver: true }).start();
  }, []);
  return (
    <Animated.View style={{ opacity: anim, transform: [{ translateY: anim.interpolate({ inputRange: [0, 1], outputRange: [30, 0] }) }] }}>
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>{section.title}</Text>
        <View style={styles.sectionCard}>
          {section.items.map((item, iIdx) => (
            <TouchableOpacity key={iIdx} activeOpacity={0.6} style={styles.menuItem} onPress={() => alert(item.label)}>
              <View style={[styles.menuIconWrapper, { backgroundColor: `${item.color}15` }]}>
                <Icon name={item.icon} size={20} color={item.color} />
              </View>
              <View style={styles.menuContent}>
                <Text style={styles.menuLabel}>{item.label}</Text>
                {item.subtitle && <Text style={styles.menuSubtitle}>{item.subtitle}</Text>}
              </View>
              <Icon name="chevron-right" size={20} color="rgba(255,255,255,0.2)" />
            </TouchableOpacity>
          ))}
        </View>
      </View>
    </Animated.View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  header: { paddingTop: 60 },
  headerGradient: { alignItems: 'center', paddingVertical: 30, paddingHorizontal: 24, borderBottomLeftRadius: 32, borderBottomRightRadius: 32 },
  avatarContainer: { position: 'relative' },
  avatar: { width: 90, height: 90, borderRadius: 30, justifyContent: 'center', alignItems: 'center' },
  avatarText: { fontSize: 32, fontWeight: '800', color: '#0a1a0f' },
  editAvatarBtn: { position: 'absolute', bottom: -2, right: -2, width: 28, height: 28, borderRadius: 10, backgroundColor: 'rgba(255,255,255,0.15)', justifyContent: 'center', alignItems: 'center', borderWidth: 2, borderColor: '#0a1a0f' },
  name: { fontSize: 24, fontWeight: '800', color: '#fff', marginTop: 16 },
  email: { fontSize: 14, color: 'rgba(255,255,255,0.5)', marginTop: 4 },
  phone: { fontSize: 13, color: 'rgba(255,255,255,0.35)', marginTop: 2 },
  statsRow: { flexDirection: 'row', alignItems: 'center', marginTop: 24, backgroundColor: 'rgba(255,255,255,0.05)', borderRadius: 18, padding: 16, borderWidth: 1, borderColor: 'rgba(255,255,255,0.06)' },
  statItem: { flex: 1, alignItems: 'center' },
  statValue: { fontSize: 20, fontWeight: '800', color: '#00C853' },
  statLabel: { fontSize: 11, color: 'rgba(255,255,255,0.4)', marginTop: 3 },
  statDivider: { width: 1, height: 30, backgroundColor: 'rgba(255,255,255,0.08)' },
  section: { marginTop: 24, paddingHorizontal: 20 },
  sectionTitle: { fontSize: 14, fontWeight: '700', color: 'rgba(255,255,255,0.4)', textTransform: 'uppercase', letterSpacing: 1, marginBottom: 10, marginLeft: 4 },
  sectionCard: { backgroundColor: 'rgba(255,255,255,0.04)', borderRadius: 18, overflow: 'hidden', borderWidth: 1, borderColor: 'rgba(255,255,255,0.06)' },
  menuItem: { flexDirection: 'row', alignItems: 'center', padding: 16, borderBottomWidth: 1, borderBottomColor: 'rgba(255,255,255,0.04)' },
  menuIconWrapper: { width: 40, height: 40, borderRadius: 12, justifyContent: 'center', alignItems: 'center' },
  menuContent: { flex: 1, marginLeft: 14 },
  menuLabel: { fontSize: 15, fontWeight: '600', color: '#fff' },
  menuSubtitle: { fontSize: 12, color: 'rgba(255,255,255,0.35)', marginTop: 2 },
  logoutContainer: { paddingHorizontal: 20, marginTop: 28 },
  logoutButton: { flexDirection: 'row', alignItems: 'center', justifyContent: 'center', paddingVertical: 16, borderRadius: 18, backgroundColor: 'rgba(255,82,82,0.08)', borderWidth: 1, borderColor: 'rgba(255,82,82,0.15)' },
  logoutText: { fontSize: 15, fontWeight: '700', color: '#FF5252', marginLeft: 8 },
  version: { textAlign: 'center', color: 'rgba(255,255,255,0.2)', fontSize: 12, marginTop: 20 },
});
